3. Implement Slack service with Effect in src/services/slack.service.ts:
   ```typescript
   import { Context, Effect, Layer, Schedule } from "effect"
   import { HttpClient } from "@effect/platform"
   import { Integration, NotificationMessage, SlackDeliveryError } from "../schemas"

   export class SlackService extends Context.Tag("SlackService")<
     SlackService,
     {
       deliver: (integration: Integration, message: NotificationMessage) => Effect.Effect<{ success: boolean }, SlackDeliveryError>
     }
   >() {}

   export const SlackServiceLive = Layer.succeed(
     SlackService,
     SlackService.of({
       deliver: (integration, message) => {
         const slackPayload = {
           text: message.payload.title,
           blocks: [
             {
               type: "section",
               text: {
                 type: "mrkdwn",
                 text: `*${message.payload.title}*\n${message.payload.body}`,
               },
             },
           ],
         }

         return HttpClient.request.post(integration.config.webhookUrl).pipe(
           HttpClient.request.jsonBody(slackPayload),
           HttpClient.client.fetchOk,
           Effect.flatMap(() => Effect.succeed({ success: true })),
           Effect.retry(
             Schedule.exponential("1 second").pipe(
               Schedule.compose(Schedule.recurs(3)),
               Schedule.jittered
             )
           ),
           Effect.mapError((e) => new SlackDeliveryError({ message: e.message, statusCode: e.statusCode }))
         )
       },
     })
   )
   ```

