   import { Context, Effect, Layer } from "effect"
   import nodemailer from "nodemailer"
   import { Integration, NotificationMessage, EmailDeliveryError } from "../schemas"

   export class EmailService extends Context.Tag("EmailService")<
     EmailService,
     {
       deliver: (integration: Integration, message: NotificationMessage) => Effect.Effect<{ success: boolean }, EmailDeliveryError>
     }
   >() {}

   export const EmailServiceLive = Layer.effect(
     EmailService,
     Effect.gen(function* () {
       return EmailService.of({
         deliver: (integration, message) =>
           Effect.tryPromise({
             try: async () => {
               const transporter = nodemailer.createTransport({
                 host: integration.config.smtpHost,
                 port: integration.config.smtpPort,
                 auth: {
                   user: integration.config.username,
                   pass: integration.config.password,
                 },
               })
               await transporter.sendMail({
                 from: integration.config.fromAddress,
                 to: message.payload.metadata?.recipient || "default@example.com",
                 subject: message.payload.title,
                 text: message.payload.body,
               })
               return { success: true }
             },
             catch: (e) => new EmailDeliveryError({ message: String(e) }),
           }),
       })
     })
   )
